data_contract.types:
/** Parametri iniziali per il form di creazione. Valori scalari: devono poter
    essere serializzati in query string senza perdita. */
export type ModuleCreateParams = Record<string, string | number>

export type ModuleFormScreenMode =
  | { type: 'create'; params?: ModuleCreateParams }   
  | { type: 'edit'; id: number }

